  z: number;
  state: TileState;
  hydration: number; // 0-100
  nutrition: number; // 0-100
  plantType?: ItemType;
  isGhost: boolean; // True if funded but not verified by NGO
}

export interface GameState {
  balance: number; // User's impact credits (USD)
  selectedTool: ItemType | null;
  tiles: TileData[];
  projectProgress: number; // 0-100%
}

