import React, { useRef, useState } from 'react';
import { Canvas, useFrame, ThreeEvent } from '@react-three/fiber';
import { OrbitControls, Stars, Float, PerspectiveCamera, Environment } from '@react-three/drei';
import * as THREE from 'three';
import { COLORS, GRID_SIZE } from '../constants';
import { TileData, TileState, ItemType } from '../types';

// --- Sub-Components ---

const Plant = ({ type, isGhost }: { type: ItemType; isGhost: boolean }) => {
  const meshRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (meshRef.current && isGhost) {
      // Bobbing effect for ghost
      meshRef.current.position.y = 0.2 + Math.sin(state.clock.getElapsedTime() * 2) * 0.05;
    }
  });

  const materialProps = isGhost
    ? { color: COLORS.plantedGhost, transparent: true, opacity: 0.6, wireframe: true }
    : { color: COLORS.plantedReal };

  if (type === ItemType.SAPLING || type === ItemType.KEYSTONE) {
    return (
      <group ref={meshRef} position={[0, 0.5, 0]}>
        {/* Trunk */}
        <mesh position={[0, 0, 0]} castShadow>
          <cylinderGeometry args={[0.05, 0.08, 0.4, 8]} />
          <meshStandardMaterial color={isGhost ? COLORS.plantedGhost : '#5D4037'} {...(isGhost ? materialProps : {})} />
        </mesh>
        {/* Leaves */}
        <mesh position={[0, 0.4, 0]} castShadow>
          <coneGeometry args={[0.25, 0.6, 8]} />
          <meshStandardMaterial {...materialProps} />
        </mesh>
        {/* Logic for Keystone - make it bigger */}
        {type === ItemType.KEYSTONE && (
          <mesh position={[0, 0.6, 0]} scale={[0.8, 0.8, 0.8]}>
             <coneGeometry args={[0.25, 0.6, 8]} />
             <meshStandardMaterial {...materialProps} />
          </mesh>
        )}
      </group>
    );
  }

  return null; // Water/Compost just change texture, handled in TileMesh
};

const TileMesh = ({
  data,
  onClick,
  onPointerOver,
  onPointerOut
}: {
  data: TileData;
  onClick: (e: ThreeEvent<MouseEvent>) => void;
  onPointerOver: (e: ThreeEvent<PointerEvent>) => void;
  onPointerOut: (e: ThreeEvent<PointerEvent>) => void;
}) => {
  const [hovered, setHovered] = useState(false);
  const meshRef = useRef<THREE.Mesh>(null);

  // Animate color transition
  useFrame(() => {
    if (meshRef.current) {
      const targetColor = new THREE.Color(
        data.state === TileState.DEGRADED
          ? COLORS.degraded
          : data.state === TileState.PRIMED
          ? COLORS.primed
          : COLORS.primed // Planted sits on primed soil
      );

      if (hovered) {
        meshRef.current.material.color.lerp(new THREE.Color(COLORS.highlight), 0.2);
      } else {
        meshRef.current.material.color.lerp(targetColor, 0.1);
      }
    }
  });

  // Calculate height based on state
  const height = data.state === TileState.DEGRADED ? 0.2 : 0.4;

  return (
    <group position={[data.x, 0, data.z]}>
      <mesh
        ref={meshRef}
        onClick={(e) => {
            e.stopPropagation();
            onClick(e);
        }}
        onPointerOver={(e) => {
            e.stopPropagation();
            setHovered(true);
            onPointerOver(e);
        }}
        onPointerOut={(e) => {
            e.stopPropagation();
            setHovered(false);
            onPointerOut(e);
        }}
        position={[0, height / 2, 0]}
        receiveShadow
        castShadow
      >
        <boxGeometry args={[0.9, height, 0.9]} />
        {/* We use a basic material that we update in useFrame */}
        <meshStandardMaterial roughness={0.8} />
      </mesh>

      {/* Visual Indicator for Water/Compost applied but not planted */}
      {data.state === TileState.PRIMED && !data.plantType && (
        <mesh position={[0, height + 0.01, 0]} rotation={[-Math.PI/2, 0, 0]}>
             <planeGeometry args={[0.7, 0.7]} />
             <meshBasicMaterial color="#8B4513" opacity={0.5} transparent />
        </mesh>
      )}

      {/* Render Plant */}
      {data.plantType && <Plant type={data.plantType} isGhost={data.isGhost} />}
    </group>
  );
};

// --- Main Scene Component ---

