import React, { useState, useCallback, useMemo } from 'react';
import { IslandScene } from './components/IslandScene';
import { BotanistKit } from './components/BotantistKit';
import { HUD } from './components/HUD';
import { GRID_SIZE, INITIAL_BALANCE, INVENTORY } from './constants';
import { TileData, TileState, ItemType, GameState } from './types';

const generateInitialTiles = (): TileData[] => {
  const tiles: TileData[] = [];
  let id = 0;
  for (let x = -Math.floor(GRID_SIZE / 2); x <= Math.floor(GRID_SIZE / 2); x++) {
    for (let z = -Math.floor(GRID_SIZE / 2); z <= Math.floor(GRID_SIZE / 2); z++) {
      tiles.push({
        id: id++,
        x,
        z,
        state: TileState.DEGRADED,
        hydration: 10,
        nutrition: 10,
        isGhost: false,
      });
    }
  }
  return tiles;
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    balance: INITIAL_BALANCE,
    selectedTool: null,
    tiles: generateInitialTiles(),
    projectProgress: 0,
  });

  const [notification, setNotification] = useState<string | null>(null);

  // Helper to flash notification
  const showNotification = (msg: string) => {
    setNotification(msg);
    setTimeout(() => setNotification(null), 3000);
  };

  const handleToolSelect = (tool: ItemType) => {
    setGameState(prev => ({ ...prev, selectedTool: tool }));
  };

  const handleTileClick = useCallback((id: number) => {
    setGameState(prev => {
      if (!prev.selectedTool) {
        showNotification("Select a tool from the Seed Vault first.");
        return prev;
      }

      const tiles = [...prev.tiles];
      const tileIndex = tiles.findIndex(t => t.id === id);
      const tile = { ...tiles[tileIndex] };
      const tool = INVENTORY.find(i => i.id === prev.selectedTool);

      if (!tool) return prev;

      // Validation Logic
      let success = false;
      let newBalance = prev.balance;
      let message = "";

      if (prev.balance < tool.price) {
        showNotification("Insufficient funds.");
        return prev;
      }

      switch (prev.selectedTool) {
        case ItemType.WATER:
          if (tile.state === TileState.DEGRADED) {
            tile.hydration = 100;
            // Need compost next? Still degraded visually but hydrated internally or change state?
            // Let's say Water moves it halfway to Primed, but needs Compost to be truly Primed.
            // Simplified: Water + Compost = Primed.
            if (tile.nutrition > 50) {
                 tile.state = TileState.PRIMED;
                 message = "Soil revitalized! Ready for planting.";
            } else {
                 message = "Soil hydrated. Needs nutrients (Compost).";
            }
            success = true;
          } else {
            message = "Soil already hydrated.";
          }
          break;

        case ItemType.COMPOST:
            tile.nutrition = 100;
            if (tile.hydration > 50) {
                tile.state = TileState.PRIMED;
                message = "Nutrients added! Soil structure restored.";
            } else {
                message = "Nutrients added. Soil too dry (Needs Water).";
            }
            success = true;
            break;

        case ItemType.SAPLING:
        case ItemType.KEYSTONE:
            if (tile.state === TileState.PRIMED && !tile.plantType) {
                tile.plantType = prev.selectedTool;
                tile.state = TileState.PLANTED;
                tile.isGhost = true; // Hologram until verified
                message = `${tool.name} funded! Waiting for satellite verification.`;
                success = true;
            } else if (tile.state === TileState.DEGRADED) {
                message = "Cannot plant on degraded soil. Heal it first.";
            } else if (tile.plantType) {
                message = "Already occupied.";
            }
            break;
      }

      if (success) {
        newBalance -= tool.price;
        showNotification(message);

        // Calculate progress
        const plantedCount = tiles.filter(t => t.plantType).length;
        const totalTiles = tiles.length;
        const progress = (plantedCount / totalTiles) * 100;

        return {
          ...prev,
          balance: newBalance,
          tiles: tiles.map((t, i) => i === tileIndex ? tile : t),
          projectProgress: progress
        };
      } else {
        showNotification(message);
        return prev;
      }
    });
  }, []);

  return (
    <div className="relative w-full h-screen bg-slate-900 overflow-hidden">
      {/* 3D Layer */}
      <IslandScene tiles={gameState.tiles} onTileClick={handleTileClick} />

      {/* UI Layer */}
      <HUD balance={gameState.balance} projectProgress={gameState.projectProgress} />

      <BotanistKit 
        balance={gameState.balance} 
        selectedTool={gameState.selectedTool} 
        onSelect={handleToolSelect} 
      />

      {/* Notification Overlay */}
      {notification && (
        <div className="fixed top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 pointer-events-none z-50">
           <div className="bg-slate-900/90 border border-emerald-500 text-white px-6 py-4 rounded-xl shadow-2xl backdrop-blur-xl animate-bounce">
              <p className="text-center font-bold">{notification}</p>
           </div>
        </div>
      )}

      {/* Start Overlay (Simple) */}
      {gameState.projectProgress === 0 && gameState.balance === INITIAL_BALANCE && !gameState.selectedTool && (
          <div className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm flex items-center justify-center pointer-events-none">
              <div className="text-center">
                  <h2 className="text-4xl font-bold text-white mb-2 tracking-widest uppercase">Tap to Restore</h2>
                  <p className="text-emerald-400 animate-pulse">Select a tool from the Seed Vault</p>
              </div>
          </div>
      )}
    </div>
  );
};

export default App;

