import React, { useState, useCallback, useMemo } from 'react';
import { IslandScene } from './components/IslandScene';
import { HUD } from './components/HUD';
import { TreeVault } from './components/TreeVault';
import { CommunityImpact } from './components/CommunityImpact';
import { GRID_SIZE, INITIAL_BALANCE, TREE_SPECIES } from './constants';
import { TileData, ItemType, GameState } from './types';

const generateInitialTiles = (): TileData[] => {
  const tiles: TileData[] = [];
  let id = 0;
  for (let x = -Math.floor(GRID_SIZE / 2); x <= Math.floor(GRID_SIZE / 2); x++) {
    for (let z = -Math.floor(GRID_SIZE / 2); z <= Math.floor(GRID_SIZE / 2); z++) {
      tiles.push({
        id: id++,
        x,
        z,
        isPlanted: false,
      });
    }
  }
  return tiles;
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    balance: INITIAL_BALANCE,
    treesPlanted: 0,
    totalCo2: 0,
    level: 1,
    tiles: generateInitialTiles(),
    showCommunity: false,
    isVaultOpen: false,
  });

  const [selectedTree, setSelectedTree] = useState<ItemType | null>(null);

  const plantedCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    gameState.tiles.forEach(t => {
      if (t.plantType) {
        counts[t.plantType] = (counts[t.plantType] || 0) + 1;
      }
    });
    return counts as Record<ItemType, number>;
  }, [gameState.tiles]);

  const handleTileClick = useCallback((id: number) => {
    if (!selectedTree) {
      setGameState(prev => ({ ...prev, isVaultOpen: true }));
      return;
    }

    setGameState(prev => {
      const treeDef = TREE_SPECIES.find(t => t.id === selectedTree);
      if (!treeDef || prev.balance < treeDef.price) return prev;

      const tiles = [...prev.tiles];
      const idx = tiles.findIndex(t => t.id === id);
      if (tiles[idx].plantType) return prev; // Already planted

      tiles[idx] = { ...tiles[idx], plantType: selectedTree, isPlanted: true };

      return {
        ...prev,
        balance: prev.balance - treeDef.price,
        treesPlanted: prev.treesPlanted + 1,
        totalCo2: prev.totalCo2 + treeDef.co2Factor,
        tiles,
        // Level up every 8 trees
        level: Math.floor((prev.treesPlanted + 1) / 8) + 1
      };
    });
  }, [selectedTree]);

  return (
    <div className="relative w-full h-screen bg-[#f3f7f2] overflow-hidden">
      <IslandScene tiles={gameState.tiles} onTileClick={handleTileClick} />

      <HUD 
        forestName="Hornbeam Forest"
        balance={gameState.balance}
        treesPlanted={gameState.treesPlanted}
        totalCo2={gameState.totalCo2}
        onCommunityClick={() => setGameState(p => ({ ...p, showCommunity: true }))}
      />

      <TreeVault 
        isOpen={gameState.isVaultOpen}
        onToggle={() => setGameState(p => ({ ...p, isVaultOpen: !p.isVaultOpen }))}
        level={gameState.level}
        balance={gameState.balance}
        plantedCounts={plantedCounts}
        onSelect={(type) => {
          setSelectedTree(type);
          setGameState(p => ({ ...p, isVaultOpen: false }));
        }}
      />

      <CommunityImpact 
        isVisible={gameState.showCommunity}
        onClose={() => setGameState(p => ({ ...p, showCommunity: false }))}
      />

      {/* Ghost selection indicator */}
      {selectedTree && (
        <div className="fixed top-8 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-2 rounded-full text-xs font-bold tracking-widest uppercase z-40 animate-pulse">
          Placing {TREE_SPECIES.find(t => t.id === selectedTree)?.name}
          <button 
            onClick={(e) => { e.stopPropagation(); setSelectedTree(null); }}
            className="ml-4 text-emerald-400"
          >
            Cancel
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

