  CEDAR = 'CEDAR',
  MAPLE = 'MAPLE',
  SPRUCE = 'SPRUCE',
  WILLOW = 'WILLOW'
}

export interface TreeType {
  id: ItemType;
  name: string;
  price: number;
  co2Factor: number; // kg per year
  unlockLevel: number;
  icon: string;
}

export interface TileData {
  id: number;
  x: number;
  z: number;
  plantType?: ItemType;
  isPlanted: boolean;
  rotation?: number;
  scale?: number;
  offsetX?: number;
  offsetZ?: number;
}

export interface GameState {
  balance: number;
  treesPlanted: number;
