              <Loader2 className="animate-spin text-emerald-600" size={40} />
              <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">Analyzing Biome...</p>
            </div>
          )}

          {insight && !loading && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-700">
              <div className="bg-slate-50 border-l-4 border-emerald-500 p-6 rounded-r-2xl mb-8">
                <p className="text-slate-700 font-serif text-lg leading-relaxed italic">
                  "{insight.split('\n')[0]}"
