                  <p className="text-[10px] font-bold uppercase text-emerald-700 tracking-wider mb-1">Botanist Tip</p>
                  <p className="text-sm text-emerald-900 leading-snug font-medium">
                    {insight.split('\n').slice(1).join(' ') || "Diversify your canopy to invite rare avian species."}
