  );
};

const Cloud = ({ position, speed }: { position: [number, number, number], speed: number }) => {
  const ref = useRef<THREE.Group>(null);
  useFrame(({ clock }) => {
    if (ref.current) {
      ref.current.position.x = position[0] + Math.cos(clock.getElapsedTime() * speed) * 5;
      ref.current.position.z = position[2] + Math.sin(clock.getElapsedTime() * speed) * 5;
    }
  });

  return (
    <group ref={ref} position={position}>
      <mesh>
        <sphereGeometry args={[0.5, 7, 7]} />
        <meshStandardMaterial color="white" roughness={1} opacity={0.6} transparent />
      </mesh>
    </group>
  );
};

const DynamicIsland = ({ tiles, onTileClick }: { tiles: TileData[], onTileClick: (id: number) => void }) => {
  const groupRef = useRef<THREE.Group>(null);
  const { mouse } = useThree();

  useFrame(() => {
    if (groupRef.current) {
      groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, mouse.y * 0.05, 0.1);
      groupRef.current.rotation.z = THREE.MathUtils.lerp(groupRef.current.rotation.z, -mouse.x * 0.05, 0.1);
    }
  });

  return (
    <group ref={groupRef}>
      <Float speed={1.5} rotationIntensity={0.1} floatIntensity={0.2}>
        <group position={[0, 0, 0]}>
          {tiles.map(tile => (
            <Tile key={tile.id} data={tile} onClick={onTileClick} />
          ))}
        </group>

        <group position={[0, -0.2, 0]}>
          <mesh position={[0, -1.2, 0]} scale={[4, 2, 4]} rotation={[Math.PI, 0, 0]}>
            <dodecahedronGeometry args={[1, 1]} />
            <meshStandardMaterial color="#889E94" flatShading roughness={1} />
          </mesh>
          <mesh position={[0, -1.5, 0]} rotation={[-Math.PI / 2, 0, 0]}>
            <circleGeometry args={[6, 32]} />
            <meshStandardMaterial color="#A5CAD2" opacity={0.2} transparent roughness={0} metalness={0.5} />
          </mesh>
          <Sparkles count={40} scale={10} size={1} speed={0.4} color="#D1FFBD" opacity={0.3} />
        </group>
      </Float>
    </group>
  );
};

const Tile: React.FC<{ data: TileData; onClick: (id: number) => void }> = ({ data, onClick }) => {
  const [hovered, setHovered] = React.useState(false);

  return (
    <group position={[data.x + (data.offsetX || 0), 0, data.z + (data.offsetZ || 0)]}>
      <mesh
        onClick={(e) => { e.stopPropagation(); onClick(data.id); }}
        onPointerOver={() => setHovered(true)}
        onPointerOut={() => setHovered(false)}
        receiveShadow
      >
        <boxGeometry args={[0.92, 0.4, 0.92]} />
        <meshStandardMaterial color={hovered ? '#D0E0D8' : COLORS.island} roughness={0.8} />
      </mesh>
      {data.plantType && <LowPolyTree type={data.plantType} rotation={data.rotation} targetScale={data.scale} />}
    </group>
  );
};

export const IslandScene: React.FC<{ tiles: TileData[], onTileClick: (id: number) => void }> = ({ tiles, onTileClick }) => {
  return (
    <div className="w-full h-full absolute inset-0 z-0 bg-[#f3f7f2]">
      <Canvas dpr={[1, 2]} shadows>
        <PerspectiveCamera makeDefault position={[12, 12, 12]} fov={30} />
        <color attach="background" args={[COLORS.sky]} />
        <Environment preset="park" />
        <ambientLight intensity={0.8} />
        <directionalLight position={[10, 20, 10]} intensity={1.5} castShadow shadow-mapSize={[1024, 1024]} />

        <OrbitControls enablePan={false} minPolarAngle={Math.PI / 6} maxPolarAngle={Math.PI / 2.2} minDistance={10} maxDistance={22} autoRotate autoRotateSpeed={0.2} />

        <DynamicIsland tiles={tiles} onTileClick={onTileClick} />

        <Cloud position={[-8, 6, -6]} speed={0.05} />
        <Cloud position={[8, 4, 4]} speed={0.03} />

        <ContactShadows position={[0, -4, 0]} opacity={0.1} scale={25} blur={4} far={12} />
      </Canvas>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
// Added missing X icon import
import { X } from 'lucide-react';
import { IslandScene } from './components/IslandScene';
import { HUD } from './components/HUD';
import { BotanistKit } from './components/BotantistKit';
import { CommunityImpact } from './components/CommunityImpact';
import { EcoAssistant } from './components/EcoAssistant';
import { GRID_SIZE, INITIAL_BALANCE, TREE_SPECIES } from './constants';
import { TileData, ItemType, GameState } from './types';

const generateInitialTiles = (): TileData[] => {
  const tiles: TileData[] = [];
  let id = 0;
  for (let x = -Math.floor(GRID_SIZE / 2); x <= Math.floor(GRID_SIZE / 2); x++) {
    for (let z = -Math.floor(GRID_SIZE / 2); z <= Math.floor(GRID_SIZE / 2); z++) {
      tiles.push({
        id: id++,
        x,
        z,
        isPlanted: false,
        rotation: Math.random() * Math.PI * 2,
        scale: 0.9 + Math.random() * 0.3,
        offsetX: (Math.random() - 0.5) * 0.2,
        offsetZ: (Math.random() - 0.5) * 0.2,
      });
    }
  }
  return tiles;
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState & { showAssistant: boolean }>({
    balance: INITIAL_BALANCE,
    treesPlanted: 0,
    totalCo2: 0,
    level: 1,
    tiles: generateInitialTiles(),
    showCommunity: false,
    isVaultOpen: false,
    showAssistant: false,
  });

  const [selectedTree, setSelectedTree] = useState<ItemType | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      setGameState(prev => {
        if (prev.totalCo2 <= 0) return prev;
        const earnings = prev.totalCo2 * 0.005;
        return {
          ...prev,
          balance: prev.balance + earnings
        };
      });
    }, 10000);
    return () => clearInterval(timer);
  }, []);

  const handleTileClick = useCallback((id: number) => {
    if (!selectedTree) return;

    setGameState(prev => {
      const treeDef = TREE_SPECIES.find(t => t.id === selectedTree);
      if (!treeDef || prev.balance < treeDef.price) return prev;

      const tiles = [...prev.tiles];
      const idx = tiles.findIndex(t => t.id === id);
      if (tiles[idx].plantType) return prev;

      tiles[idx] = { ...tiles[idx], plantType: selectedTree, isPlanted: true };

      return {
        ...prev,
        balance: prev.balance - treeDef.price,
        treesPlanted: prev.treesPlanted + 1,
        totalCo2: prev.totalCo2 + treeDef.co2Factor,
        tiles,
        level: Math.floor((prev.treesPlanted + 1) / 8) + 1
      };
    });
    setSelectedTree(null); // Deselect after planting for better mobile experience
  }, [selectedTree]);

  const activeTreeData = useMemo(() => TREE_SPECIES.find(t => t.id === selectedTree), [selectedTree]);

  return (
    <div className="relative w-full h-screen bg-[#f3f7f2] overflow-hidden select-none">
      <IslandScene tiles={gameState.tiles} onTileClick={handleTileClick} />

      <HUD 
        forestName="Terra Archipelago"
        balance={gameState.balance}
        treesPlanted={gameState.treesPlanted}
        totalCo2={gameState.totalCo2}
        onCommunityClick={() => setGameState(p => ({ ...p, showCommunity: true }))}
        onAssistantClick={() => setGameState(p => ({ ...p, showAssistant: true }))}
      />

      <BotanistKit 
        balance={gameState.balance}
        selectedTool={selectedTree}
        onSelect={(type) => setSelectedTree(type === selectedTree ? null : type)}
      />

      <CommunityImpact 
        isVisible={gameState.showCommunity}
        onClose={() => setGameState(p => ({ ...p, showCommunity: false }))}
      />

      {gameState.showAssistant && (
        <EcoAssistant 
          tiles={gameState.tiles}
          onClose={() => setGameState(p => ({ ...p, showAssistant: false }))}
        />
      )}

      {/* Improved Placement Indicator */}
      {selectedTree && (
        <div className="fixed top-28 left-1/2 -translate-x-1/2 z-50 flex items-center gap-4 bg-emerald-950 text-white px-8 py-3 rounded-full shadow-2xl border border-white/20 animate-in slide-in-from-top-4">
          <span className="text-xl animate-bounce">{activeTreeData?.icon}</span>
          <div className="flex flex-col">
            <span className="text-[10px] uppercase font-bold text-emerald-400 tracking-widest">Architect Mode</span>
            <span className="text-xs font-bold">Deploying {activeTreeData?.name} Species...</span>
          </div>
          <button 
            onClick={() => setSelectedTree(null)}
            className="ml-4 p-1 hover:bg-white/10 rounded-full transition-colors"
          >
            <X size={16} />
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

