import React, { useRef, useMemo, useState } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Float, PerspectiveCamera, Environment, ContactShadows, Sparkles } from '@react-three/drei';
import * as THREE from 'three';
import { COLORS } from '../constants';
import { TileData, ItemType } from '../types';

const LowPolyTree = ({ type, rotation = 0, targetScale = 1 }: { type: ItemType; rotation?: number; targetScale?: number }) => {
  const meshRef = useRef<THREE.Group>(null);
  const [currentScale, setCurrentScale] = useState(0);

  useFrame((_, delta) => {
    if (currentScale < targetScale) {
      setCurrentScale(prev => Math.min(targetScale, prev + delta * 1.5));
    }
    if (meshRef.current) {
      meshRef.current.scale.set(currentScale, currentScale, currentScale);
    }
  });

  const treeConfig = useMemo(() => {
    switch (type) {
      case ItemType.CEDAR: return { height: 1.4, width: 0.25, detail: 4, leaves: 3, leafColor: '#3A5A40' };
      case ItemType.MAPLE: return { height: 0.9, width: 0.5, detail: 8, leaves: 1, leafColor: '#A44A3F' };
      case ItemType.SPRUCE: return { height: 1.6, width: 0.3, detail: 3, leaves: 4, leafColor: '#2D6A4F' };
      case ItemType.WILLOW: return { height: 1.1, width: 0.45, detail: 6, leaves: 2, leafColor: '#52796F' };
      default: return { height: 1, width: 0.4, detail: 6, leaves: 2, leafColor: COLORS.treeLeaves };
    }
  }, [type]);

  return (
    <group ref={meshRef} rotation={[0, rotation, 0]}>
      <mesh position={[0, treeConfig.height / 2.5, 0]}>
        <cylinderGeometry args={[0.04, 0.07, treeConfig.height * 0.8, 6]} />
        <meshStandardMaterial color={COLORS.treeTrunk} roughness={0.9} />
      </mesh>

      {Array.from({ length: treeConfig.leaves }).map((_, i) => (
        <mesh 
          key={i} 
          position={[0, treeConfig.height * (0.6 + i * 0.2), 0]}
          rotation={[0, (i * Math.PI) / 3, 0]}
        >
          <coneGeometry args={[treeConfig.width * (1 - i * 0.2), treeConfig.height * 0.6, treeConfig.detail]} />
          <meshStandardMaterial color={treeConfig.leafColor} flatShading />
        </mesh>
      ))}
    </group>
  );
};

const DynamicIsland = ({ 
  tiles, 
  onTileClick, 
  islandColor, 
  waterColor, 
  accentColor 
}: { 
  tiles: TileData[], 
  onTileClick: (id: number) => void,
  islandColor: string,
  waterColor: string,
  accentColor: string
}) => {
  const groupRef = useRef<THREE.Group>(null);
  const { mouse } = useThree();

  useFrame(() => {
    if (groupRef.current) {
      groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, mouse.y * 0.05, 0.1);
      groupRef.current.rotation.z = THREE.MathUtils.lerp(groupRef.current.rotation.z, -mouse.x * 0.05, 0.1);
    }
  });

  return (
    <group ref={groupRef}>
      <Float speed={1.5} rotationIntensity={0.1} floatIntensity={0.2}>
        <group position={[0, 0, 0]}>
          {tiles.map(tile => (
            <Tile key={tile.id} data={tile} onClick={onTileClick} islandColor={islandColor} />
          ))}
        </group>

        <group position={[0, -0.2, 0]}>
          <mesh position={[0, -1.2, 0]} scale={[4, 2, 4]} rotation={[Math.PI, 0, 0]}>
            <dodecahedronGeometry args={[1, 1]} />
            <meshStandardMaterial color={islandColor} flatShading roughness={1} />
          </mesh>
          <mesh position={[0, -1.5, 0]} rotation={[-Math.PI / 2, 0, 0]}>
            <circleGeometry args={[6, 32]} />
            <meshStandardMaterial color={waterColor} opacity={0.2} transparent roughness={0} metalness={0.5} />
          </mesh>
          <Sparkles count={40} scale={10} size={1} speed={0.4} color={accentColor} opacity={0.3} />
        </group>
      </Float>
    </group>
  );
};

const Tile: React.FC<{ data: TileData; onClick: (id: number) => void; islandColor: string }> = ({ data, onClick, islandColor }) => {
  const [hovered, setHovered] = React.useState(false);

  return (
    <group position={[data.x + (data.offsetX || 0), 0, data.z + (data.offsetZ || 0)]}>
      <mesh
        onClick={(e) => { e.stopPropagation(); onClick(data.id); }}
        onPointerOver={() => setHovered(true)}
        onPointerOut={() => setHovered(false)}
        receiveShadow
      >
        <boxGeometry args={[0.92, 0.4, 0.92]} />
        <meshStandardMaterial color={hovered ? '#E8F3F0' : islandColor} roughness={0.8} />
      </mesh>
      {data.plantType && <LowPolyTree type={data.plantType} rotation={data.rotation} targetScale={data.scale} />}
    </group>
  );
};

export const IslandScene: React.FC<{ 
  tiles: TileData[], 
  onTileClick: (id: number) => void,
  islandColor: string,
  waterColor: string,
  accentColor: string
}> = ({ tiles, onTileClick, islandColor, waterColor, accentColor }) => {
  return (
    <div className="w-full h-full absolute inset-0 z-0">
      <Canvas dpr={[1, 2]} shadows>
        <PerspectiveCamera makeDefault position={[12, 12, 12]} fov={30} />
        <color attach="background" args={[COLORS.sky]} />
        <Environment preset="park" />
        <ambientLight intensity={0.8} />
        <directionalLight position={[10, 20, 10]} intensity={1.5} castShadow shadow-mapSize={[1024, 1024]} />

        <OrbitControls enablePan={false} minPolarAngle={Math.PI / 6} maxPolarAngle={Math.PI / 2.2} minDistance={10} maxDistance={22} autoRotate autoRotateSpeed={0.2} />

        <DynamicIsland 
          tiles={tiles} 
          onTileClick={onTileClick} 
          islandColor={islandColor}
          waterColor={waterColor}
          accentColor={accentColor}
        />

        <ContactShadows position={[0, -4, 0]} opacity={0.1} scale={25} blur={4} far={12} />
      </Canvas>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { X, LogOut, Map as MapIcon, ChevronLeft, ChevronRight, Share2 } from 'lucide-react';
import { IslandScene } from './components/IslandScene';
import { HUD } from './components/HUD';
