import { CommunityImpact } from './components/CommunityImpact';
import { EcoAssistant } from './components/EcoAssistant';
import { ImpactMap } from './components/ImpactMap';
import { Login } from './components/Login';
import { ORGANIZATIONS, INITIAL_BALANCE, TREE_SPECIES } from './constants';
import { TileData, ItemType, GameState, Organization } from './types';

type View = 'island' | 'map';

const App: React.FC = () => {
  const [user, setUser] = useState<{ name: string; email: string } | null>(null);
  const [currentView, setCurrentView] = useState<View>('island');
  const [activeOrgIndex, setActiveOrgIndex] = useState(0);
  const [orgs, setOrgs] = useState<Organization[]>(ORGANIZATIONS);

  const [gameState, setGameState] = useState<GameState>({
    balance: INITIAL_BALANCE,
    level: 1,
    showCommunity: false,
    isVaultOpen: false,
    showAssistant: false,
  });

  const [selectedTree, setSelectedTree] = useState<ItemType | null>(null);

  const activeOrg = orgs[activeOrgIndex];

  const handleTileClick = useCallback((id: number) => {
    if (!selectedTree) return;

    const treeDef = TREE_SPECIES.find(t => t.id === selectedTree);
    if (!treeDef || gameState.balance < treeDef.price) return;

    setOrgs(prev => {
      const newOrgs = [...prev];
      const org = { ...newOrgs[activeOrgIndex] };
      const tiles = [...org.tiles];
      const idx = tiles.findIndex(t => t.id === id);

      if (tiles[idx].plantType) return prev;

      tiles[idx] = { ...tiles[idx], plantType: selectedTree, isPlanted: true };
      org.tiles = tiles;
      org.totalTrees += 1;
      org.totalCo2 += treeDef.co2Factor;

      newOrgs[activeOrgIndex] = org;
      return newOrgs;
    });

    setGameState(prev => ({
      ...prev,
      balance: prev.balance - treeDef.price,
    }));

    setSelectedTree(null);
  }, [selectedTree, activeOrgIndex, gameState.balance]);

  const activeTreeData = useMemo(() => TREE_SPECIES.find(t => t.id === selectedTree), [selectedTree]);

  const nextOrg = () => setActiveOrgIndex((prev) => (prev + 1) % orgs.length);
  const prevOrg = () => setActiveOrgIndex((prev) => (prev - 1 + orgs.length) % orgs.length);

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  return (
    <div className="relative w-full h-screen bg-[#f3f7f2] overflow-hidden select-none">
      {currentView === 'island' ? (
        <>
          <IslandScene 
            tiles={activeOrg.tiles} 
            onTileClick={handleTileClick} 
            islandColor={activeOrg.islandColor}
            waterColor={activeOrg.waterColor}
            accentColor={activeOrg.accentColor}
          />

          <HUD 
            forestName={activeOrg.name}
            balance={gameState.balance}
            treesPlanted={activeOrg.totalTrees}
            totalCo2={activeOrg.totalCo2}
            onCommunityClick={() => setGameState(p => ({ ...p, showCommunity: true }))}
            onAssistantClick={() => setGameState(p => ({ ...p, showAssistant: true }))}
          />

          {/* Organization Switcher UI */}
          <div className="fixed inset-y-0 left-0 flex items-center px-4 md:px-8 z-30 pointer-events-none">
            <button 
              onClick={prevOrg}
              className="pointer-events-auto bg-white/80 backdrop-blur-md p-4 rounded-full shadow-lg hover:bg-white transition-all active:scale-90"
            >
              <ChevronLeft size={24} className="text-slate-800" />
            </button>
          </div>
          <div className="fixed inset-y-0 right-0 flex items-center px-4 md:px-8 z-30 pointer-events-none">
            <button 
              onClick={nextOrg}
              className="pointer-events-auto bg-white/80 backdrop-blur-md p-4 rounded-full shadow-lg hover:bg-white transition-all active:scale-90"
            >
              <ChevronRight size={24} className="text-slate-800" />
            </button>
          </div>

          {/* Org Identity Badge */}
          <div className="fixed top-28 left-6 md:left-12 z-30 pointer-events-none animate-in fade-in slide-in-from-left">
            <div className="bg-white/90 backdrop-blur-md p-6 rounded-[32px] shadow-xl border border-emerald-50 max-w-xs pointer-events-auto">
              <span className="text-[10px] font-bold uppercase tracking-widest text-emerald-600 mb-2 block">Organization Focus</span>
              <h2 className="text-xl font-serif text-slate-900 mb-1">{activeOrg.name}</h2>
              <p className="text-xs text-slate-500 italic mb-4">"{activeOrg.mission}"</p>
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{activeOrg.location}</span>
              </div>
            </div>
          </div>

          <BotanistKit 
            balance={gameState.balance}
            selectedTool={selectedTree}
            onSelect={(type) => setSelectedTree(type === selectedTree ? null : type)}
          />

          <button 
            onClick={() => setCurrentView('map')}
            className="fixed top-32 right-6 md:right-12 z-30 pointer-events-auto bg-white/90 backdrop-blur-md p-4 rounded-3xl shadow-xl border border-emerald-100 hover:bg-emerald-50 transition-all flex items-center gap-3 group"
          >
            <MapIcon size={20} className="text-emerald-700" />
            <span className="text-[10px] font-bold uppercase tracking-widest text-emerald-900 overflow-hidden w-0 group-hover:w-24 transition-all duration-300 whitespace-nowrap">
              Impact Map
            </span>
          </button>
        </>
      ) : (
        <ImpactMap onBack={() => setCurrentView('island')} />
      )}

      <button 
        onClick={() => setUser(null)}
        className="fixed bottom-6 right-6 z-50 p-3 bg-white/50 backdrop-blur-md hover:bg-white text-slate-400 hover:text-red-500 rounded-full transition-all border border-slate-200"
        title="Logout"
      >
        <LogOut size={18} />
      </button>

      <CommunityImpact 
        isVisible={gameState.showCommunity}
        onClose={() => setGameState(p => ({ ...p, showCommunity: false }))}
      />

      {gameState.showAssistant && (
        <EcoAssistant 
          tiles={activeOrg.tiles}
          onClose={() => setGameState(p => ({ ...p, showAssistant: false }))}
        />
      )}

      {selectedTree && currentView === 'island' && (
        <div className="fixed top-12 left-1/2 -translate-x-1/2 z-50 flex items-center gap-4 bg-emerald-950 text-white px-8 py-3 rounded-full shadow-2xl border border-white/20 animate-in slide-in-from-top-4">
          <span className="text-xl animate-bounce">{activeTreeData?.icon}</span>
          <div className="flex flex-col">
            <span className="text-[10px] uppercase font-bold text-emerald-400 tracking-widest">Architect Mode</span>
            <span className="text-xs font-bold">Deploying to {activeOrg.name}...</span>
          </div>
          <button 
            onClick={() => setSelectedTree(null)}
            className="ml-4 p-1 hover:bg-white/10 rounded-full transition-colors"
          >
            <X size={16} />
          </button>
        </div>
      )}
    </div>
  );
};

