import React, { useRef, useMemo, useState, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { 
  OrbitControls, 
  Float, 
  PerspectiveCamera, 
  Environment, 
  ContactShadows, 
  Sparkles,
  RoundedBox
} from '@react-three/drei';
import * as THREE from 'three';
import { COLORS } from '../constants';
import { TileData, ItemType } from '../types';

const LowPolyTree = ({ type, rotation = 0, targetScale = 1 }: { type: ItemType; rotation?: number; targetScale?: number }) => {
  const meshRef = useRef<THREE.Group>(null);
  const [currentScale, setCurrentScale] = useState(0);

  useFrame((_, delta) => {
    if (currentScale < targetScale) {
      setCurrentScale(prev => Math.min(targetScale, prev + delta * 2));
    }
    if (meshRef.current) {
      meshRef.current.scale.set(currentScale, currentScale, currentScale);
    }
  });

  const treeConfig = useMemo(() => {
    switch (type) {
      case ItemType.CEDAR: return { height: 1.6, width: 0.35, detail: 4, leaves: 3, leafColor: '#2D6A4F' };
      case ItemType.MAPLE: return { height: 1.1, width: 0.6, detail: 8, leaves: 1, leafColor: '#A44A3F' };
      case ItemType.SPRUCE: return { height: 1.8, width: 0.4, detail: 3, leaves: 4, leafColor: '#1B4332' };
      case ItemType.WILLOW: return { height: 1.3, width: 0.55, detail: 6, leaves: 2, leafColor: '#52796F' };
      default: return { height: 1.2, width: 0.5, detail: 6, leaves: 2, leafColor: '#409167' };
    }
  }, [type]);

  return (
    <group ref={meshRef} rotation={[0, rotation, 0]} position={[0, 0.4, 0]}>
      <mesh position={[0, treeConfig.height / 2.5, 0]}>
        <cylinderGeometry args={[0.06, 0.1, treeConfig.height * 0.8, 6]} />
        <meshStandardMaterial color="#5D4037" roughness={0.9} />
      </mesh>

      {Array.from({ length: treeConfig.leaves }).map((_, i) => (
        <mesh 
          key={i} 
          position={[0, treeConfig.height * (0.6 + i * 0.2), 0]}
          rotation={[0, (i * Math.PI) / 3, 0]}
        >
          <coneGeometry args={[treeConfig.width * (1 - i * 0.2), treeConfig.height * 0.7, treeConfig.detail]} />
          <meshStandardMaterial color={treeConfig.leafColor} flatShading />
        </mesh>
      ))}
    </group>
  );
};

const Tile: React.FC<{ data: TileData; onClick: (id: number) => void; islandColor: string }> = ({ data, onClick, islandColor }) => {
  const [hovered, setHovered] = React.useState(false);

  // Random decorative elements based on tile ID
  const decor = useMemo(() => {
    const random = (seed: number) => {
        const x = Math.sin(seed) * 10000;
        return x - Math.floor(x);
    };
    const hasBush = random(data.id) > 0.7;
    const hasRock = random(data.id + 100) > 0.85;
    return { hasBush, hasRock, bushSize: 0.1 + random(data.id) * 0.1 };
  }, [data.id]);

  return (
    <group position={[data.x, 0, data.z]}>
      {/* Tile Base (Dirt) */}
      <RoundedBox 
        args={[0.95, 0.6, 0.95]} 
        radius={0.15} 
        smoothness={4} 
        position={[0, -0.1, 0]}
        onClick={(e) => { e.stopPropagation(); onClick(data.id); }}
        onPointerOver={() => setHovered(true)}
        onPointerOut={() => setHovered(false)}
      >
        <meshStandardMaterial color="#8D6E63" roughness={0.8} />
      </RoundedBox>

      {/* Tile Top (Grass) - The "Toy" Look */}
      <RoundedBox 
        args={[0.95, 0.3, 0.95]} 
        radius={0.2} 
        smoothness={4} 
        position={[0, 0.2, 0]}
        receiveShadow
      >
        <meshStandardMaterial color={hovered ? '#DCE775' : islandColor} roughness={0.6} />
      </RoundedBox>

      {/* Decorative Bushes (Inspiration) */}
      {!data.plantType && decor.hasBush && (
        <mesh position={[0.2, 0.4, -0.2]} scale={decor.bushSize}>
          <sphereGeometry args={[1, 8, 8]} />
          <meshStandardMaterial color="#43A047" flatShading />
        </mesh>
      )}
      {!data.plantType && decor.hasRock && (
        <mesh position={[-0.25, 0.38, 0.2]} rotation={[Math.random(), 0, 0]} scale={0.1}>
          <dodecahedronGeometry args={[1]} />
          <meshStandardMaterial color="#BDBDBD" flatShading />
        </mesh>
      )}

      {data.plantType && <LowPolyTree type={data.plantType} rotation={data.rotation} targetScale={data.scale} />}
    </group>
  );
};

const DynamicIsland = ({ 
  tiles, 
  onTileClick, 
  islandColor, 
  waterColor, 
  accentColor,
  transitionOffset
}: { 
  tiles: TileData[], 
  onTileClick: (id: number) => void,
  islandColor: string,
  waterColor: string,
  accentColor: string,
  transitionOffset: number
}) => {
  const groupRef = useRef<THREE.Group>(null);
  const targetPos = useRef(new THREE.Vector3(0, 0, 0));

  useFrame((state, delta) => {
    if (groupRef.current) {
        // Horizontal slide transition
        targetPos.current.x = transitionOffset * 15;
        groupRef.current.position.lerp(targetPos.current, 0.1);

        // Gentle hover animation
        groupRef.current.position.y = Math.sin(state.clock.getElapsedTime() * 0.5) * 0.2;

        // Subtle tilt based on mouse
        groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, state.mouse.y * 0.1, 0.1);
        groupRef.current.rotation.z = THREE.MathUtils.lerp(groupRef.current.rotation.z, -state.mouse.x * 0.1, 0.1);
    }
  });

  return (
    <group ref={groupRef}>
        <group position={[0, 0, 0]}>
          {tiles.map(tile => (
            <Tile key={tile.id} data={tile} onClick={onTileClick} islandColor={islandColor} />
          ))}
        </group>

        {/* Floating Base Platform */}
        <group position={[0, -0.8, 0]}>
          <RoundedBox args={[6, 0.8, 6]} radius={0.5} smoothness={4} position={[0, -0.4, 0]}>
            <meshStandardMaterial color={waterColor} opacity={0.6} transparent roughness={0.1} metalness={0.2} />
          </RoundedBox>
          <Sparkles count={50} scale={8} size={2} speed={0.3} color={accentColor} opacity={0.4} />
        </group>
    </group>
  );
};

