import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { X, LogOut, Map as MapIcon, ChevronLeft, ChevronRight } from 'lucide-react';
import { IslandScene } from './components/IslandScene';
import { HUD } from './components/HUD';
import { BotanistKit } from './components/BotantistKit';
import { CommunityImpact } from './components/CommunityImpact';
import { EcoAssistant } from './components/EcoAssistant';
import { ImpactMap } from './components/ImpactMap';
import { Login } from './components/Login';
import { ORGANIZATIONS, INITIAL_BALANCE, TREE_SPECIES } from './constants';
import { TileData, ItemType, GameState, Organization } from './types';

type View = 'island' | 'map';

const App: React.FC = () => {
  const [user, setUser] = useState<{ name: string; email: string } | null>(null);
  const [currentView, setCurrentView] = useState<View>('island');
  const [activeOrgIndex, setActiveOrgIndex] = useState(0);
  const [orgs, setOrgs] = useState<Organization[]>(ORGANIZATIONS);

  const [gameState, setGameState] = useState<GameState>({
    balance: INITIAL_BALANCE,
    level: 1,
    showCommunity: false,
    isVaultOpen: false,
    showAssistant: false,
  });

  const [selectedTree, setSelectedTree] = useState<ItemType | null>(null);

  const activeOrg = orgs[activeOrgIndex];

  const handleTileClick = useCallback((id: number) => {
    if (!selectedTree) return;

    const treeDef = TREE_SPECIES.find(t => t.id === selectedTree);
    if (!treeDef || gameState.balance < treeDef.price) return;

    setOrgs(prev => {
      const newOrgs = [...prev];
      const org = { ...newOrgs[activeOrgIndex] };
      const tiles = [...org.tiles];
      const idx = tiles.findIndex(t => t.id === id);

      if (tiles[idx].plantType) return prev;

      tiles[idx] = { ...tiles[idx], plantType: selectedTree, isPlanted: true };
      org.tiles = tiles;
      org.totalTrees += 1;
      org.totalCo2 += treeDef.co2Factor;

      newOrgs[activeOrgIndex] = org;
      return newOrgs;
    });

    setGameState(prev => ({
      ...prev,
      balance: prev.balance - treeDef.price,
    }));

    setSelectedTree(null);
  }, [selectedTree, activeOrgIndex, gameState.balance]);

  const activeTreeData = useMemo(() => TREE_SPECIES.find(t => t.id === selectedTree), [selectedTree]);

  const nextOrg = () => setActiveOrgIndex((prev) => (prev + 1) % orgs.length);
  const prevOrg = () => setActiveOrgIndex((prev) => (prev - 1 + orgs.length) % orgs.length);

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  return (
    <div className="relative w-full h-screen bg-[#D1FFBD] overflow-hidden select-none">
      {currentView === 'island' ? (
        <>
          <IslandScene 
            tiles={activeOrg.tiles} 
            onTileClick={handleTileClick} 
            islandColor={activeOrg.islandColor}
            waterColor={activeOrg.waterColor}
            accentColor={activeOrg.accentColor}
            orgIndex={activeOrgIndex}
          />

          <HUD 
            forestName={activeOrg.name}
            balance={gameState.balance}
            treesPlanted={activeOrg.totalTrees}
            totalCo2={activeOrg.totalCo2}
            onCommunityClick={() => setGameState(p => ({ ...p, showCommunity: true }))}
            onAssistantClick={() => setGameState(p => ({ ...p, showAssistant: true }))}
          />

          {/* Organization Switcher Controls - Responsive Placement */}
          <div className="fixed inset-y-0 left-0 flex items-center px-2 md:px-12 z-40 pointer-events-none">
            <button 
              onClick={prevOrg}
              className="pointer-events-auto group flex flex-col items-center gap-2"
            >
              <div className="bg-white/90 backdrop-blur-md p-3 md:p-5 rounded-full shadow-xl hover:bg-white transition-all active:scale-90 border-2 border-emerald-100">
                <ChevronLeft size={24} className="md:w-8 md:h-8 text-emerald-800" />
              </div>
              <span className="hidden md:block text-[10px] font-bold text-emerald-900/40 uppercase tracking-widest group-hover:text-emerald-900 transition-colors">Previous</span>
            </button>
          </div>
          <div className="fixed inset-y-0 right-0 flex items-center px-2 md:px-12 z-40 pointer-events-none">
            <button 
              onClick={nextOrg}
              className="pointer-events-auto group flex flex-col items-center gap-2"
            >
              <div className="bg-white/90 backdrop-blur-md p-3 md:p-5 rounded-full shadow-xl hover:bg-white transition-all active:scale-90 border-2 border-emerald-100">
                <ChevronRight size={24} className="md:w-8 md:h-8 text-emerald-800" />
              </div>
              <span className="hidden md:block text-[10px] font-bold text-emerald-900/40 uppercase tracking-widest group-hover:text-emerald-900 transition-colors">Next Org</span>
            </button>
          </div>

          {/* Organization Context Card - Compact on Mobile */}
          <div className="fixed top-24 md:top-28 left-4 md:left-12 z-30 pointer-events-none transition-all duration-500">
            <div className="bg-white/95 backdrop-blur-xl p-4 md:p-8 rounded-[24px] md:rounded-[40px] shadow-2xl border-2 md:border-4 border-emerald-50 max-w-[200px] md:max-w-xs pointer-events-auto transform hover:-rotate-1 transition-transform">
              <div className="flex items-center gap-3 mb-2 md:mb-4">
                <div className="w-8 h-8 md:w-10 md:h-10 rounded-xl md:rounded-2xl flex items-center justify-center text-sm md:text-xl shadow-inner" style={{ backgroundColor: activeOrg.islandColor }}>
                    🌍
                </div>
                <div>
                   <span className="hidden md:block text-[10px] font-black uppercase tracking-[0.2em] text-emerald-600">Restoration Hub</span>
                   <h2 className="text-base md:text-2xl font-serif text-slate-900 leading-tight">{activeOrg.name}</h2>
                </div>
              </div>
              <p className="hidden md:block text-sm text-slate-600 font-medium leading-relaxed mb-6 italic">"{activeOrg.mission}"</p>

              <div className="flex items-center justify-between pt-2 md:pt-4 border-t border-slate-100">
                <div className="flex items-center gap-2">
                    <div className="w-2 h-2 md:w-3 md:h-3 rounded-full bg-emerald-500 animate-pulse"></div>
                    <span className="text-[10px] md:text-xs font-bold text-slate-400 uppercase tracking-widest truncate max-w-[100px]">{activeOrg.location}</span>
                </div>
                <div className="hidden md:block bg-emerald-50 px-3 py-1 rounded-full text-[10px] font-bold text-emerald-700">ACTIVE</div>
              </div>
            </div>
          </div>

          <BotanistKit 
            balance={gameState.balance}
            selectedTool={selectedTree}
            onSelect={(type) => setSelectedTree(type === selectedTree ? null : type)}
          />

          <button 
            onClick={() => setCurrentView('map')}
            className="fixed top-24 md:top-32 right-4 md:right-12 z-30 pointer-events-auto bg-emerald-950 p-3 md:p-5 rounded-[20px] md:rounded-[32px] shadow-2xl hover:bg-emerald-900 transition-all flex items-center gap-2 md:gap-3 group border-b-4 border-emerald-800"
          >
            <MapIcon size={20} className="md:w-6 md:h-6 text-emerald-400 group-hover:rotate-12 transition-transform" />
            <span className="hidden md:inline text-xs font-bold uppercase tracking-[0.2em] text-white">Global Impact</span>
          </button>
        </>
      ) : (
        <ImpactMap onBack={() => setCurrentView('island')} />
      )}

      <button 
        onClick={() => setUser(null)}
        className="fixed bottom-24 md:bottom-6 right-4 md:right-6 z-50 p-3 md:p-4 bg-white/80 backdrop-blur-md hover:bg-white text-slate-400 hover:text-red-500 rounded-2xl md:rounded-3xl transition-all shadow-xl border border-slate-200"
        title="Logout"
      >
        <LogOut size={18} className="md:w-5 md:h-5" />
      </button>

      <CommunityImpact 
        isVisible={gameState.showCommunity}
        onClose={() => setGameState(p => ({ ...p, showCommunity: false }))}
      />

      {gameState.showAssistant && (
        <EcoAssistant 
          tiles={activeOrg.tiles}
          onClose={() => setGameState(p => ({ ...p, showAssistant: false }))}
        />
      )}

      {selectedTree && currentView === 'island' && (
        <div className="fixed top-12 left-1/2 -translate-x-1/2 z-50 flex items-center gap-4 bg-emerald-950 text-white px-6 md:px-10 py-3 md:py-4 rounded-full shadow-2xl border-2 border-emerald-400/30 animate-in slide-in-from-top-6 w-11/12 md:w-auto max-w-sm md:max-w-none">
          <div className="text-xl md:text-2xl animate-bounce">{activeTreeData?.icon}</div>
          <div className="flex flex-col truncate">
            <span className="text-[9px] md:text-[10px] uppercase font-black text-emerald-400 tracking-[0.3em]">Arboreal Protocol</span>
            <span className="text-xs md:text-sm font-bold truncate">Planting at {activeOrg.name}...</span>
          </div>
          <button 
            onClick={() => setSelectedTree(null)}
            className="ml-auto md:ml-6 p-2 hover:bg-white/10 rounded-full transition-colors"
          >
            <X size={18} className="md:w-5 md:h-5" />
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

