                  <p className="text-[8px] md:text-[10px] text-slate-400 italic mb-2 font-mono">Unlock Level: {item.unlockLevel}</p>

                  <div className="mt-auto pt-2 border-t border-slate-700/50 w-full">
                    <p className="text-[8px] md:text-[10px] text-emerald-400 flex items-center gap-1">
                      <Info size={10} />
                      <span className="truncate">Offsets {item.co2Factor}kg CO2/yr</span>
                    </p>
                  </div>

                  {/* Hover Tooltip Effect - Hidden on mobile */}
                  <div className="hidden md:block absolute -top-12 left-0 bg-black text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap border border-slate-600 pointer-events-none">
                    Plant {item.name}
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

